/**
 * /admin/coverage — POMS citation coverage report
 *
 * Visual view of which POMS clusters have been cited by published/draft pages.
 * Reads from coverage.json generated by: npx tsx scripts/coverage-report.ts --json
 */
import { redirect } from 'next/navigation';
import { createSessionClient, createServiceClient } from '@/lib/supabase';
import * as fs from 'fs';
import * as path from 'path';

const ADMIN_EMAIL = 'jstanley@nssapros.com';
const NSSA_DARK   = '#13405E';
const G           = { bg: '#f3f4f6', border: '#e5e7eb', text: '#6b7280' };

export const dynamic = 'force-dynamic';

type Cluster = {
  total: number;
  cited: number;
  coverage_pct: number;
  tier: 1 | 2 | 3;
  label?: string;
  uncited_sample: string[];
};

type CoverageData = {
  generated_at: string;
  totals: {
    rule_docs: number;
    advisor_relevant: number;
    internal_ops: number;
    published_pages: number;
    draft_pages: number;
    cited_sections: number;
    coverage_pct: number;
  };
  clusters: Record<string, Cluster>;
  suggested_next: Array<{ cluster: string; label: string; total: number; sample: string[] }>;
};

function ProgressBar({ pct, tier }: { pct: number; tier: number }) {
  const color = pct === 0 ? '#E5E7EB'
    : pct < 10 ? '#FCA5A5'
    : pct < 40 ? '#FCD34D'
    : '#6EE7B7';
  const filled = Math.max(pct, pct > 0 ? 2 : 0);
  return (
    <div style={{ height: 8, background: '#E5E7EB', borderRadius: 4, overflow: 'hidden', width: '100%' }}>
      <div style={{ height: '100%', width: `${Math.min(filled, 100)}%`, background: color, borderRadius: 4, transition: 'width .3s' }} />
    </div>
  );
}

function StatCard({ label, value, sub }: { label: string; value: string | number; sub?: string }) {
  return (
    <div style={{ background: '#fff', border: `1px solid ${G.border}`, borderRadius: 8, padding: '16px 20px' }}>
      <div style={{ fontSize: 24, fontWeight: 700, color: NSSA_DARK, marginBottom: 2 }}>{value}</div>
      <div style={{ fontSize: 13, fontWeight: 600, color: '#374151' }}>{label}</div>
      {sub && <div style={{ fontSize: 12, color: G.text, marginTop: 2 }}>{sub}</div>}
    </div>
  );
}

export default async function CoveragePage() {
  const session = await createSessionClient();
  const { data: { user } } = await session.auth.getUser();
  if (!user?.email) redirect('/admin/login');

  const service = createServiceClient();
  const isAdmin = user.email === ADMIN_EMAIL;
  if (!isAdmin) {
    const { data: reviewer } = await service.from('kb_reviewers').select('display_name').eq('email', user.email).single();
    if (!reviewer) redirect('/admin/login?error=unauthorized');
  }

  // Read coverage.json from project root
  let data: CoverageData | null = null;
  let readError: string | null = null;
  try {
    const jsonPath = path.join(process.cwd(), 'coverage.json');
    data = JSON.parse(fs.readFileSync(jsonPath, 'utf-8')) as CoverageData;
  } catch {
    readError = 'coverage.json not found. Run: npx tsx scripts/coverage-report.ts --json';
  }

  const clusters = data ? Object.entries(data.clusters)
    .filter(([, c]) => c.tier <= 2)
    .sort((a, b) => {
      // Sort: cited first (desc coverage), then uncited by size
      if (b[1].cited !== a[1].cited) return b[1].cited - a[1].cited;
      return b[1].total - a[1].total;
    }) : [];

  const tier1 = clusters.filter(([, c]) => c.tier === 1);
  const tier2 = clusters.filter(([, c]) => c.tier === 2);
  const generatedAt = data?.generated_at ? new Date(data.generated_at).toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' }) : null;

  return (
    <div style={{ minHeight: '100vh', background: G.bg, fontFamily: 'ui-sans-serif, system-ui, sans-serif' }}>
      {/* Header */}
      <div style={{ background: NSSA_DARK, color: '#fff', padding: '14px 32px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
          <a href="/admin/kb-review" style={{ color: '#8ECAEE', textDecoration: 'none', fontSize: 14 }}>← Queue</a>
          <span style={{ color: '#4a7fa0' }}>/</span>
          <span style={{ fontWeight: 700, fontSize: 18 }}>POMS Coverage Report</span>
        </div>
        {generatedAt && (
          <span style={{ fontSize: 12, color: '#8ECAEE' }}>Generated {generatedAt}</span>
        )}
      </div>

      <div style={{ maxWidth: 1100, margin: '0 auto', padding: '28px 24px' }}>

        {readError ? (
          <div style={{ background: '#FEF3C7', border: '1px solid #FDE68A', borderRadius: 8, padding: '20px 24px', color: '#92400E' }}>
            <strong>Report not available</strong><br />
            <code style={{ fontSize: 13 }}>{readError}</code>
          </div>
        ) : data ? (
          <>
            {/* Stats row */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: 12, marginBottom: 32 }}>
              <StatCard label="Total POMS Sections" value={data.totals.rule_docs.toLocaleString()} />
              <StatCard label="Advisor-Relevant" value={data.totals.advisor_relevant.toLocaleString()} sub="Tier 1 + 2" />
              <StatCard label="Cited by Pages" value={data.totals.cited_sections} sub={`${data.totals.published_pages} published, ${data.totals.draft_pages} draft`} />
              <StatCard label="Coverage" value={`${data.totals.coverage_pct}%`} sub="of advisor-relevant sections" />
              <StatCard label="Uncovered Clusters" value={tier1.filter(([, c]) => c.cited === 0).length} sub="Tier 1 with zero coverage" />
            </div>

            {/* Suggested next */}
            {data.suggested_next?.length > 0 && (
              <div style={{ background: '#EFF6FF', border: '1px solid #BFDBFE', borderRadius: 8, padding: '18px 20px', marginBottom: 28 }}>
                <p style={{ margin: '0 0 12px', fontWeight: 700, fontSize: 13, color: '#1E40AF' }}>⚡ Suggested next drafts — largest uncovered Tier 1 clusters</p>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                  {data.suggested_next.slice(0, 8).map((s, i) => (
                    <div key={i} style={{ background: '#fff', border: '1px solid #BFDBFE', borderRadius: 6, padding: '6px 12px', fontSize: 12 }}>
                      <span style={{ fontWeight: 700, color: NSSA_DARK }}>{s.cluster}</span>
                      <span style={{ color: G.text, marginLeft: 6 }}>{s.label}</span>
                      <span style={{ color: '#1E40AF', marginLeft: 6, fontWeight: 600 }}>{s.total} sections</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Tier 1 clusters */}
            <h2 style={{ fontSize: 15, fontWeight: 700, color: '#111', margin: '0 0 12px' }}>
              Tier 1 — Core Advisor Topics ({tier1.length} clusters)
            </h2>
            <div style={{ background: '#fff', border: `1px solid ${G.border}`, borderRadius: 8, overflow: 'hidden', marginBottom: 28 }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
                <thead>
                  <tr style={{ background: G.bg, borderBottom: `1px solid ${G.border}` }}>
                    {['Cluster', 'Topic', 'Coverage', 'Cited / Total', 'Sample uncited'].map(h => (
                      <th key={h} style={{ padding: '9px 14px', textAlign: 'left', fontSize: 11, fontWeight: 700, letterSpacing: '0.07em', textTransform: 'uppercase', color: G.text }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {tier1.map(([key, c]) => (
                    <tr key={key} style={{ borderBottom: `1px solid ${G.border}` }}>
                      <td style={{ padding: '10px 14px', fontWeight: 700, color: NSSA_DARK, whiteSpace: 'nowrap', fontFamily: 'ui-monospace, monospace', fontSize: 12 }}>{key}</td>
                      <td style={{ padding: '10px 14px', color: '#374151', fontSize: 12 }}>{c.label ?? '—'}</td>
                      <td style={{ padding: '10px 14px', width: 140 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                          <div style={{ flex: 1 }}><ProgressBar pct={c.coverage_pct} tier={c.tier} /></div>
                          <span style={{ fontSize: 11, fontWeight: 700, color: c.coverage_pct === 0 ? '#9CA3AF' : c.coverage_pct < 10 ? '#DC2626' : '#059669', minWidth: 36, textAlign: 'right' }}>{c.coverage_pct}%</span>
                        </div>
                      </td>
                      <td style={{ padding: '10px 14px', color: G.text, whiteSpace: 'nowrap' }}>{c.cited} / {c.total}</td>
                      <td style={{ padding: '10px 14px', color: G.text, fontSize: 11, fontFamily: 'ui-monospace, monospace' }}>
                        {c.uncited_sample.slice(0, 3).join(', ')}
                        {c.uncited_sample.length > 3 && '…'}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Tier 2 clusters */}
            <h2 style={{ fontSize: 15, fontWeight: 700, color: '#111', margin: '0 0 12px' }}>
              Tier 2 — Moderate Advisor Value ({tier2.length} clusters)
            </h2>
            <div style={{ background: '#fff', border: `1px solid ${G.border}`, borderRadius: 8, overflow: 'hidden' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
                <thead>
                  <tr style={{ background: G.bg, borderBottom: `1px solid ${G.border}` }}>
                    {['Cluster', 'Topic', 'Coverage', 'Cited / Total'].map(h => (
                      <th key={h} style={{ padding: '9px 14px', textAlign: 'left', fontSize: 11, fontWeight: 700, letterSpacing: '0.07em', textTransform: 'uppercase', color: G.text }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {tier2.map(([key, c]) => (
                    <tr key={key} style={{ borderBottom: `1px solid ${G.border}` }}>
                      <td style={{ padding: '10px 14px', fontWeight: 700, color: NSSA_DARK, whiteSpace: 'nowrap', fontFamily: 'ui-monospace, monospace', fontSize: 12 }}>{key}</td>
                      <td style={{ padding: '10px 14px', color: '#374151', fontSize: 12 }}>{c.label ?? '—'}</td>
                      <td style={{ padding: '10px 14px', width: 140 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                          <div style={{ flex: 1 }}><ProgressBar pct={c.coverage_pct} tier={c.tier} /></div>
                          <span style={{ fontSize: 11, fontWeight: 700, color: c.coverage_pct === 0 ? '#9CA3AF' : '#059669', minWidth: 36, textAlign: 'right' }}>{c.coverage_pct}%</span>
                        </div>
                      </td>
                      <td style={{ padding: '10px 14px', color: G.text, whiteSpace: 'nowrap' }}>{c.cited} / {c.total}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <p style={{ fontSize: 12, color: G.text, marginTop: 16, textAlign: 'right' }}>
              Refresh: <code style={{ background: G.bg, padding: '2px 6px', borderRadius: 3 }}>npx tsx scripts/coverage-report.ts --json</code>
            </p>
          </>
        ) : null}
      </div>
    </div>
  );
}
